# ── Colormap class ──────────────────────────────────────────────

class _Colormap:
    """A callable colormap that maps scalar values [0,1] to RGBA tuples."""

    def __init__(self, name):
        self.name = name
        self.N = 256
        self._plotly_name = _CMAP_TO_PLOTLY.get(name, name)
        self._stops = _CMAP_STOPS.get(name, [(68,1,84), (33,145,140), (253,231,37)])

    def __call__(self, value, alpha=None, bytes=False):
        """Map a scalar or array of scalars in [0,1] to RGBA tuples."""
        if isinstance(value, _np.ndarray):
            out = _np.array([self._single(float(v)) for v in value.ravel()]).reshape(value.shape + (4,))
            if alpha is not None:
                out[..., 3] = alpha
            if bytes:
                return (_np.clip(out, 0, 1) * 255).astype(_np.uint8)
            return out
        if hasattr(value, '__iter__') and not isinstance(value, str):
            out = _np.array([self._single(float(v)) for v in value])
            if alpha is not None:
                out[:, 3] = alpha
            if bytes:
                return (_np.clip(out, 0, 1) * 255).astype(_np.uint8)
            return out
        rgba = self._single(float(value))
        if alpha is not None:
            rgba = rgba[:3] + (alpha,)
        if bytes:
            return tuple(int(c * 255) for c in rgba)
        return rgba

    def _single(self, v):
        """Map a single float in [0,1] to (r, g, b, a) with values in [0,1]."""
        v = max(0.0, min(1.0, v))
        stops = self._stops
        n = len(stops) - 1
        idx = v * n
        i = min(int(idx), n - 1)
        t = idx - i
        r = (stops[i][0] * (1 - t) + stops[i+1][0] * t) / 255.0
        g = (stops[i][1] * (1 - t) + stops[i+1][1] * t) / 255.0
        b = (stops[i][2] * (1 - t) + stops[i+1][2] * t) / 255.0
        return (r, g, b, 1.0)

    def reversed(self, name=None):
        """Return a reversed copy of this colormap."""
        rname = name or self.name + '_r'
        cmap = _Colormap(rname)
        cmap._stops = list(reversed(self._stops))
        cmap._plotly_name = self._plotly_name
        return cmap

    def resampled(self, lutsize):
        """Return a resampled copy."""
        cmap = _Colormap(self.name)
        cmap.N = lutsize
        cmap._stops = self._stops
        cmap._plotly_name = self._plotly_name
        return cmap

    @property
    def plotly_colorscale(self):
        return self._plotly_name

    def __str__(self):
        return self.name

    def __repr__(self):
        return f"<matplotlib.cm._Colormap '{self.name}'>"

    def __eq__(self, other):
        if isinstance(other, _Colormap):
            return self.name == other.name
        return NotImplemented

    def __hash__(self):
        return hash(self.name)


# Aliases
Colormap = _Colormap
LinearSegmentedColormap = _Colormap
ListedColormap = _Colormap

# ── Public API ──────────────────────────────────────────────────

# Global colormap registry
_cmap_registry = {}


def _ensure_registry():
    """Lazily populate the registry on first use."""
    if _cmap_registry:
        return
    # Register every known colormap name
    all_names = set(list(_CMAP_TO_PLOTLY.keys()) + list(_CMAP_STOPS.keys()))
    for name in all_names:
        _cmap_registry[name] = _Colormap(name)
        # Also register _r (reversed) variants
        rname = name + '_r'
        _cmap_registry[rname] = _cmap_registry[name].reversed(rname)


def get_cmap(name='viridis', lut=None):
    """Return a colormap object by name."""
    if isinstance(name, _Colormap):
        return name
    _ensure_registry()
    name = str(name)
    if name in _cmap_registry:
        cmap = _cmap_registry[name]
        if lut is not None:
            return cmap.resampled(lut)
        return cmap
    # Unknown name — create on the fly
    return _Colormap(name)


def register_cmap(name=None, cmap=None, **kwargs):
    """Register a colormap in the registry."""
    _ensure_registry()
    if cmap is not None:
        if name is None:
            name = cmap.name
        _cmap_registry[name] = cmap
    elif name is not None:
        _cmap_registry[name] = _Colormap(name)


def to_plotly(name):
    """Convert a matplotlib colormap name to its plotly equivalent string.
    Plotly 6.x accepts lowercase colorscale names."""
    if isinstance(name, _Colormap):
        pname = name.plotly_colorscale
        return pname.lower() if isinstance(pname, str) else pname
    result = _CMAP_TO_PLOTLY.get(str(name), str(name))
    return result.lower() if isinstance(result, str) else result


def to_rgba(value, cmap='viridis', alpha=None):
    """Convenience: map scalar(s) in [0,1] to RGBA via named colormap."""
    cm = get_cmap(cmap)
    return cm(value, alpha=alpha)


class ScalarMappable:
    """Lightweight ScalarMappable for colorbar/legend support."""

    def __init__(self, norm=None, cmap=None):
        self.norm = norm
        self.cmap = get_cmap(cmap) if isinstance(cmap, str) else (cmap or get_cmap())
        self._A = None

    def set_array(self, A):
        self._A = A

    def get_array(self):
        return self._A

    def get_cmap(self):
        return self.cmap

    def set_cmap(self, cmap):
        self.cmap = get_cmap(cmap) if isinstance(cmap, str) else cmap

    def to_rgba(self, x, alpha=None, bytes=False):
        x = _np.asarray(x, dtype=float)
        if self.norm is not None:
            x = self.norm(x)
        return self.cmap(x, alpha=alpha, bytes=bytes)

    def changed(self):
        pass

    def autoscale(self):
        pass

    def autoscale_None(self):
        pass


# ── Module-level colormap attributes ───────────────────────────
# This makes cm.viridis, cm.plasma, cm.jet, etc. work as callables.

class _CmapModule:
    """Proxy that exposes every registered colormap as an attribute."""

    def __getattr__(self, name):
        if name.startswith('_'):
            raise AttributeError(name)
        _ensure_registry()
        if name in _cmap_registry:
            return _cmap_registry[name]
        # Try creating on the fly
        cmap = _Colormap(name)
        _cmap_registry[name] = cmap
        return cmap

    def __dir__(self):
        _ensure_registry()
        return list(_cmap_registry.keys()) + ['get_cmap', 'to_plotly', 'to_rgba',
                'ScalarMappable', 'register_cmap', 'Colormap',
                'LinearSegmentedColormap', 'ListedColormap']


import sys as _sys
# Replace this module with the proxy so attribute access works
_self = _sys.modules[__name__]
_proxy = _CmapModule()
# Copy all public names to the proxy
for _k in list(vars(_self).keys()):
    if not _k.startswith('__'):
        try:
            setattr(_proxy, _k, getattr(_self, _k))
        except (AttributeError, TypeError):
            pass

# Keep original module accessible for function resolution
_proxy.__name__ = __name__
_proxy.__file__ = __file__
_proxy.__package__ = __package__
_proxy.__spec__ = getattr(_self, '__spec__', None)
_proxy.__path__ = getattr(_self, '__path__', [])
_proxy.__loader__ = getattr(_self, '__loader__', None)
_sys.modules[__name__] = _proxy
